// // This module decodes a 5-bit input into a 32-bit output, but it does not ensure that only one output line is high.
module decoder_5to32 (
    input [4:0] in,
    output reg [31:0] out
);
    always @(*) begin
        out = 32'b0; // Initialize output to all zeros
        out[in] = 1'b1; // Set the corresponding output to high
    end
endmodule
